import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { api } from "../api";
import Header from "../components/Header";
import TopNavBar from "../components/TopNavBar";

export default function AddTransaction() {
  const [form, setForm] = useState({
    name: "",
    amount: "",
    interestRate: "",
    interestType: "Simple",
    date: "",
    givenOrTaken: "Given",
  });
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  function onChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  async function onSubmit(e) {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("token");
      await api.post("/transactions", form, {
        headers: { Authorization: `Bearer ${token}` },
      });
      navigate("/"); // Redirect to homepage or "/portfolio" after adding
    } catch (err) {
      setError("Failed to add transaction");
    } finally {
      setLoading(false);
    }
  }

  return (
    <>
      <Header />
      <TopNavBar />
      <div
        style={{
          maxWidth: 470,
          minHeight: "70vh",
          margin: "32px auto",
          background: "#fff",
          borderRadius: 24,
          padding: 32,
          boxShadow: "0 2px 16px #7286D340",
          display: "flex",
          flexDirection: "column",
        }}
      >
        <h2 style={{ textAlign: "left", marginBottom: 18, color: "#323875" }}>
          Add Transaction
        </h2>
        <form
          onSubmit={onSubmit}
          style={{ display: "flex", flexDirection: "column", gap: 17 }}
        >
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>Name</label>
            <input
              name="name"
              value={form.name}
              onChange={onChange}
              required
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            />
          </div>
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>Amount</label>
            <input
              name="amount"
              value={form.amount}
              type="number"
              min="0"
              onChange={onChange}
              required
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            />
          </div>
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>
              Interest Rate (%)
            </label>
            <input
              name="interestRate"
              value={form.interestRate}
              type="number"
              min="0"
              onChange={onChange}
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            />
          </div>
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>
              Interest Type
            </label>
            <select
              name="interestType"
              value={form.interestType}
              onChange={onChange}
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            >
              <option value="Simple">Simple</option>
              <option value="Compound">Compound</option>
            </select>
          </div>
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>Date</label>
            <input
              name="date"
              value={form.date}
              type="date"
              onChange={onChange}
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            />
          </div>
          <div>
            <label style={{ fontWeight: 600, fontSize: 14 }}>Type</label>
            <select
              name="givenOrTaken"
              value={form.givenOrTaken}
              onChange={onChange}
              style={{
                fontSize: 15,
                border: "1px solid #dfdfed",
                borderRadius: 11,
                padding: 9,
                width: "100%",
                background: "#F7F8FA",
              }}
            >
              <option value="Given">Given</option>
              <option value="Taken">Taken</option>
            </select>
          </div>
          {error && <div style={{ color: "red", marginTop: 5 }}>{error}</div>}
          <button
            type="submit"
            disabled={loading}
            style={{
              background: "#5D5FEF",
              padding: "12px 0",
              fontWeight: 700,
              borderRadius: 16,
              border: "none",
              color: "#fff",
              fontSize: 18,
              marginTop: 8,
              cursor: "pointer",
            }}
          >
            {loading ? "Saving..." : "Add Transaction"}
          </button>
        </form>
      </div>
    </>
  );
}
